async (params, browser) => {
  // Open store page
  await browser.open(`${params.store_url}`)

  // Wait for store page
  await browser.waitForSelector('[class*=\'store-name\'], [class*=\'shop-name\'], h1', 15000)

  await browser.wait(2000)

  // Scroll for products
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract store profile
  const store_data = await browser.evaluate(`const nameEl = document.querySelector('[class*="store-name"], [class*="shop-name"], h1'); const ratingEl = document.querySelector('[class*="store-rating"], [class*="score"]'); const followersEl = document.querySelector('[class*="followers"], [class*="follower"]'); const feedbackEl = document.querySelector('[class*="feedback"], [class*="positive"]'); const sinceEl = document.querySelector('[class*="since"], [class*="open-date"]'); const products = []; document.querySelectorAll('[class*="product-card"], [class*="item-card"], a[href*="/item/"]').forEach(function(el) { const titleEl = el.querySelector('[class*="title"], h3'); const priceEl = el.querySelector('[class*="price"]'); const imgEl = el.querySelector('img'); const linkEl = el.tagName === 'A' ? el : el.querySelector('a'); if (products.length < 10) { products.push({ title: titleEl ? titleEl.textContent.trim().substring(0, 150) : '', price: priceEl ? priceEl.textContent.trim() : '', url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } }); return { store_name: nameEl ? nameEl.textContent.trim() : '', rating: ratingEl ? ratingEl.textContent.trim() : '', followers: followersEl ? followersEl.textContent.trim() : '', feedback: feedbackEl ? feedbackEl.textContent.trim() : '', open_since: sinceEl ? sinceEl.textContent.trim() : '', product_count: products.length, top_products: products, url: window.location.href }`)

  return store_data
}
